parameters.jsCode:
// JSON 파싱
const content = $input.item.json.content || [];
let raw = content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();
raw = raw.replace(/^```[a-z]*\s*/i, '').replace(/\s*```$/, '').trim();
const s = raw.indexOf('{');
const e = raw.lastIndexOf('}');
if (s < 0 || e < 0) throw new Error('JSON을 찾을 수 없음');
const parsed = JSON.parse(raw.slice(s, e + 1));
if (!Array.isArray(parsed.categories)) throw new Error('categories 없음');

// updatedAt 추가
parsed.updatedAt = new Date().toISOString();

// 이메일 HTML 생성
const today = new Date();
const dateStr = today.toLocaleDateString('ko-KR', {year:'numeric',month:'long',day:'numeric',weekday:'long'});
const siteUrl = process.env.SITE_URL || 'https://your-site.vercel.app';

let itemsHtml = '';
parsed.categories.forEach(cat => {
  itemsHtml += `<tr><td style="padding:20px 0 8px"><p style="margin:0;font-size:10px;font-weight:700;letter-spacing:0.25em;color:#b5451b;text-transform:uppercase;border-bottom:1px solid #c8c0b0;padding-bottom:8px">${cat.name}</p></td></tr>`;
  (cat.items || []).forEach(item => {
    const hl = item.url ? `<a href="${item.url}" style="color:#1a1a1a;text-decoration:none;border-bottom:1px solid #c8c0b0">${item.headline}</a>` : item.headline;
    itemsHtml += `<tr><td style="padding:10px 0 14px;border-bottom:1px solid #ede8dc">
      <p style="margin:0 0 6px;font-size:15px;font-weight:600;line-height:1.5;color:#1a1a1a">${hl}</p>
      <p style="margin:0 0 6px;font-size:13px;line-height:1.7;color:#4a4540;font-weight:300">${item.summary}</p>
      ${item.why ? `<p style="margin:4px 0 0;font-size:11px;color:#7a7068;font-style:italic;padding-left:8px;border-left:2px solid #c9a84c">${item.why}</p>` : ''}
      ${item.url ? `<p style="margin:8px 0 0"><a href="${item.url}" style="font-size:11px;color:#b5451b;text-decoration:none">기사 원문 →</a></p>` : ''}
    </td></tr>`;
  });
});

const emailHtml = `<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f0ebe2">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f0ebe2">
<tr><td align="center" style="padding:30px 16px">
<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background:#f5f0e8">
  <tr><td style="padding:32px 36px 20px;border-bottom:3px double #c8c0b0;text-align:center">
    <p style="margin:0 0 6px;font-size:10px;letter-spacing:0.3em;color:#7a7068;text-transform:uppercase">Daily Intelligence</p>
    <h1 style="margin:0;font-size:36px;font-weight:700;color:#1a1a1a;letter-spacing:-0.02em">오늘의 브리핑</h1>
    <p style="margin:10px 0 0;font-size:12px;color:#7a7068;letter-spacing:0.1em">${dateStr}</p>
  </td></tr>
  <tr><td style="padding:0 36px 24px">
    <table width="100%" cellpadding="0" cellspacing="0">${itemsHtml}</table>
  </td></tr>
  <tr><td style="padding:16px 36px;border-top:3px double #c8c0b0;text-align:center">
    <p style="margin:0 0 8px;font-size:11px;color:#7a7068">AI가 오늘의 주요 뉴스를 선별합니다</p>
    <a href="${siteUrl}" style="font-size:12px;color:#b5451b;text-decoration:none;letter-spacing:0.05em">웹에서 보기 →</a>
  </td></tr>
</table>
</td></tr>
</table></body></html>`;

return [{ json: { briefingData: parsed, emailHtml, dateStr } }];
